import { initializeApp, getApps, getApp } from "firebase/app";
import type { FirebaseApp } from "firebase/app";
import { getAuth, signInAnonymously } from "firebase/auth";
import { getFirestore } from "firebase/firestore";
import { getStorage } from "firebase/storage";
import type { FirebaseStorage } from "firebase/storage";
import { initializeAppCheck, ReCaptchaV3Provider, getToken } from "firebase/app-check";
import type { AppCheck } from "firebase/app-check";

// Standardize config access
const firebaseConfig = {
  apiKey: process.env.VITE_FIREBASE_API_KEY,
  authDomain: process.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: process.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: process.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.VITE_FIREBASE_APP_ID
};

const isValidConfig = !!(firebaseConfig.apiKey && firebaseConfig.projectId);

let app: FirebaseApp | undefined;
let appCheckInstance: AppCheck | undefined;

if (isValidConfig) {
  try {
    app = getApps().length > 0 ? getApp() : initializeApp(firebaseConfig);

    if (typeof window !== 'undefined' && app) {
      try {
        const siteKey = process.env.VITE_RECAPTCHA_SITE_KEY;
        if (siteKey && siteKey !== 'undefined' && siteKey !== '') {
          appCheckInstance = initializeAppCheck(app, {
            provider: new ReCaptchaV3Provider(siteKey),
            isTokenAutoRefreshEnabled: true
          });
        }
      } catch (appCheckError) {
        console.warn("App Check failed to initialize, continuing without it.", appCheckError);
      }
    }
  } catch (e) {
    console.error("Firebase Initialization Failed:", e);
  }
} else {
  console.warn("Firebase credentials missing. Using local fallback mode.");
}

export const auth = app ? getAuth(app) : null;
export const db = app ? getFirestore(app) : null;

let storageInstance: FirebaseStorage | null = null;
if (app && firebaseConfig.storageBucket && firebaseConfig.storageBucket.trim() !== "") {
  try {
    storageInstance = getStorage(app);
  } catch (e) {
    console.log("Firebase Storage skipped (Optional).");
  }
}
export const storage = storageInstance;

export const getAppCheckToken = async () => {
  if (!appCheckInstance) return null;
  try {
    const result = await getToken(appCheckInstance, false);
    return result.token;
  } catch (e) {
    console.warn("Failed to retrieve App Check token:", e);
    return null;
  }
};

export const ensureAuth = async () => {
  if (!auth) return null;
  try {
    if (!auth.currentUser) {
      const userCredential = await signInAnonymously(auth);
      return userCredential.user;
    }
    return auth.currentUser;
  } catch (error) {
    console.error("Firebase Auth Error:", error);
    return null;
  }
};

