export const IELTSSimulator: React.FC<IELTSSimulatorProps> = ({ onReport, onExit }) => {
  const [stage, setStage] = useState<SimStage>('selection');
  const [isModelReady, setIsModelReady] = useState(false);
  const [isAiLoopActive, setIsAiLoopActive] = useState(false); 
  const [hardwareError, setHardwareError] = useState<string | null>(null);
  const [part, setPart] = useState<1 | 2>(1);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [question, setQuestion] = useState<any>(null);
  const [askedQuestions, setAskedQuestions] = useState<Set<string>>(new Set());
  const [showText, setShowText] = useState(false);
  const [prepTime, setPrepTime] = useState(60);
  const [recordTime, setRecordTime] = useState(0);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isFetchingAudio, setIsFetchingAudio] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const streamRef = useRef<MediaStream | null>(null);
  const isMountedRef = useRef<boolean>(true);
  const audioContextRef = useRef<AudioContext | null>(null);
  const userId = useRef(getAnonymousUserId());

  const sessionMetricsRef = useRef({
    eyeContactSum: 0,
    smileSum: 0,
    frameCount: 0
  });

  const handleModelReady = useCallback(() => {
    setIsModelReady(true);
  }, []);

  const faceMetrics = useFaceMesh(
    videoRef, 
    canvasRef, 
    isAiLoopActive, 
    stream, 
    handleModelReady
  );

  useEffect(() => {
    if (stage === 'recording' && isAiLoopActive && isModelReady) {
      sessionMetricsRef.current.eyeContactSum += faceMetrics.hasEyeContact ? 1 : 0;
      sessionMetricsRef.current.smileSum += faceMetrics.smileIntensity;
      sessionMetricsRef.current.frameCount += 1;
    }
  }, [faceMetrics, stage, isAiLoopActive, isModelReady]);

  const stopAllHardware = useCallback(() => {
    setIsAiLoopActive(false);
    setIsModelReady(false);

    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => {
        try { 
          track.stop(); 
          track.enabled = false; 
        } catch (e) {}
      });
      streamRef.current = null;
    }

    if (mediaRecorderRef.current) {
      if (mediaRecorderRef.current.state !== 'inactive') {
        try { mediaRecorderRef.current.stop(); } catch (e) {}
      }
      mediaRecorderRef.current = null;
    }

    if (videoRef.current) {
      videoRef.current.srcObject = null;
      videoRef.current.load();
    }

    setStream(null);
  }, []);

  const initializeHardware = async () => {
    try {
      setHardwareError(null);
      setIsModelReady(false);
      setIsAiLoopActive(false);

      stopAllHardware();
      await new Promise(r => setTimeout(r, 1200));

      const vStream = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 1280 }, height: { ideal: 720 } }
      });

      const aStream = await navigator.mediaDevices.getUserMedia({
        audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true, channelCount: 1 }
      });

      if (!isMountedRef.current) {
        vStream.getTracks().forEach(t => t.stop());
        aStream.getTracks().forEach(t => t.stop());
        return;
      }

      const combinedStream = new MediaStream([...vStream.getVideoTracks(), ...aStream.getAudioTracks()]);
      streamRef.current = combinedStream;
      setStream(combinedStream);

      if (videoRef.current) {
        videoRef.current.srcObject = vStream;
        await videoRef.current.play().catch(e => console.warn("Video blocked", e));
      }

      const mimeType = ['audio/webm;codecs=opus', 'audio/webm', 'audio/mp4'].find(m => MediaRecorder.isTypeSupported(m));
      const recorder = new MediaRecorder(aStream, { mimeType });
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => { 
        if (e.data.size > 0) audioChunksRef.current.push(e.data); 
      };

      recorder.onstop = () => {
        const finalBlob = new Blob(audioChunksRef.current, { type: recorder.mimeType });
        processAudit(finalBlob, recorder.mimeType);
      };

      await new Promise(r => setTimeout(r, 1000));
      if (recorder.state === 'inactive' && aStream.active) {
        try {
          recorder.start(1000);
        } catch (startError: any) {
          const fallbackRecorder = new MediaRecorder(aStream);
          mediaRecorderRef.current = fallbackRecorder;
          fallbackRecorder.ondataavailable = recorder.ondataavailable;
          fallbackRecorder.onstop = recorder.onstop;
          fallbackRecorder.start(1000);
        }
      }

      await new Promise(r => setTimeout(r, 1000));
      setIsAiLoopActive(true);

    } catch (e: any) {
      console.error("IELTS Hardware Fail:", e);
      setHardwareError(e.message || "Hardware Access Denied.");
      setStage('selection'); 
    }
  };

  useEffect(() => {
    isMountedRef.current = true;
    return () => { isMountedRef.current = false; stopAllHardware(); };
  }, [stopAllHardware]);

  useEffect(() => {
    if (stage === 'recording') {
      initializeHardware();
      sessionMetricsRef.current = { eyeContactSum: 0, smileSum: 0, frameCount: 0 };
    } else if (stage !== 'processing') {
      stopAllHardware();
    }
  }, [stage, stopAllHardware]);

  const processAudit = async (blob: Blob, rawMimeType: string) => {
    if (blob.size === 0) { setStage('selection'); return; }
    try {
      const sanitizedMime = rawMimeType.split(';')[0];
      const base64 = await processRecordingBlob(blob);
      const questionText = typeof question === 'string' ? question : question?.topic;

      const avgEyeContact = sessionMetricsRef.current.frameCount > 0 
        ? (sessionMetricsRef.current.eyeContactSum / sessionMetricsRef.current.frameCount) * 100 
        : 100;
      const avgSmile = sessionMetricsRef.current.frameCount > 0 
        ? (sessionMetricsRef.current.smileSum / sessionMetricsRef.current.frameCount) * 100 
        : 0;

      const result = await coachService.analyzeIELTS(base64, sanitizedMime, {
        part,
        question: questionText,
        duration: recordTime
      });

      onReport({
        ...(result as any),
        id: Math.random().toString(36).substring(2, 11),
        userId: userId.current,
        date: new Date().toISOString(),
        language: 'en', 
        duration: recordTime,
        question_text: questionText,
        ielts_part: part,
        ielts_subscores: {
          fluency: (result as any).ielts_score || 5.0,
          lexical: (result as any).ielts_score || 5.0,
          grammar: (result as any).ielts_score || 5.0,
          pronunciation: (result as any).ielts_score || 5.0
        },
        filler_count: 0,
        pause_count: 0,
        eyeContactScore: avgEyeContact,
        smileScore: avgSmile
      });
    } catch (e) {
      console.error("IELTS Audit Fail:", e);
      setStage('selection');
    }
  };

  const handleStop = () => {
    setStage('processing');
    stopAllHardware();
  };

  const handleGlobalExit = () => {
    if (stage === 'recording' || stage === 'prep') {
      if (!window.confirm("Abort current IELTS simulation? Data will be lost.")) return;
    }
    stopAllHardware();
    onExit();
  };

  useEffect(() => {
    let t: number;
    if (stage === 'recording') t = window.setInterval(() => setRecordTime(p => p + 1), 1000);
    return () => clearInterval(t);
  }, [stage]);

  const handleStartPart = (p: 1 | 2) => {
    setPart(p);
    setStage('method-selection');
  };

  const startRandomQuestion = () => {
    const dataPool = part === 1 ? IELTS_QUESTIONS.part1 : IELTS_QUESTIONS.part2;
    const allCategories = Object.keys(dataPool);
    const randomCat = allCategories[Math.floor(Math.random() * allCategories.length)];
    const questionsInCat = (dataPool as any)[randomCat];
    const q = questionsInCat[Math.floor(Math.random() * questionsInCat.length)];
    beginQuestion(q);
  };

  const beginQuestion = async (q: any) => {
    setQuestion(q);
    const qText = typeof q === 'string' ? q : q.topic;
    setAskedQuestions(prev => new Set(prev).add(qText));
    setStage('question');
    setIsFetchingAudio(true);
    setIsSpeaking(true);

    try {
      const ai = coachService.getAI();
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ 
          parts: [{ 
            text: `Speak as an official UK male IELTS examiner with a clear British English accent. Read this question naturally and professionally: ${qText}` 
          }] 
        }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
              voiceConfig: {
                prebuiltVoiceConfig: { voiceName: 'Charon' },
              },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

      if (base64Audio) {
        if (!audioContextRef.current) {
          const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
          audioContextRef.current = new AudioContextClass({sampleRate: 24000});
        }
        const ctx = audioContextRef.current;
        const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        source.onended = () => {
          if (isMountedRef.current) setIsSpeaking(false);
        };
        setIsFetchingAudio(false);
        source.start();
      } else {
        throw new Error("No audio data returned");
      }
    } catch (err) {
      console.error("Examiner TTS Fallback:", err);
      setIsFetchingAudio(false);
      const u = new SpeechSynthesisUtterance(qText);
      u.lang = 'en-GB';
      u.onend = () => setIsSpeaking(false);
      window.speechSynthesis.speak(u);
    }
  };

  const getExaminerState = () => {
    if (isFetchingAudio || stage === 'processing') return 'thinking';
    if (isSpeaking) return 'speaking';
    if (stage === 'recording' || stage === 'prep') return 'listening';
    return 'idle';
  };

  return (
    <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col items-center justify-center p-6">
      <div className="absolute top-6 left-6 flex items-center gap-6">
        <button onClick={handleGlobalExit} className="p-3 rounded-2xl bg-slate-900 border border-slate-800 text-slate-500 hover:text-white transition-all shadow-xl active:scale-95 group">
          <X size={20} className="group-hover:rotate-90 transition-transform" />
        </button>
        <div className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-900 border border-slate-800">
          <Globe size={14} className="text-indigo-400" />
          <span className="text-[10px] font-black uppercase tracking-widest text-white">Mode: English (Standard)</span>
        </div>
      </div>

      {hardwareError && (
        <div className="absolute top-24 max-w-md w-full p-6 bg-rose-500/10 border border-rose-500/20 rounded-3xl flex flex-col gap-4 z-[110] animate-in slide-in-from-top-4 shadow-2xl">
          <div className="flex items-start gap-4">
             <AlertCircle className="text-rose-500 shrink-0 mt-0.5" size={20} />
             <div className="text-sm">
                <p className="font-bold text-rose-400 text-base">Hardware Ignite Failed</p>
                <p className="text-rose-200/60 mt-1 text-xs">{hardwareError}</p>
             </div>
          </div>
          <button onClick={initializeHardware} className="w-full py-3 rounded-xl bg-rose-500 text-white font-bold flex items-center justify-center gap-2 hover:bg-rose-600 transition-colors shadow-lg shadow-rose-500/20"><RefreshCw size={16} /> Force Reset</button>
        </div>
      )}

      {stage === 'selection' && (
        <div className="max-w-4xl w-full text-center animate-in fade-in zoom-in duration-700">
          <ShieldCheck size={48} className="text-indigo-500 mx-auto mb-6" />
          <h1 className="text-4xl font-black text-white mb-4 italic tracking-tight">IELTS Simulation</h1>
          <p className="text-slate-400 mb-12">English Proficiency Assessment (Strict UK Standard)</p>
          <div className="grid md:grid-cols-2 gap-6">
            <button onClick={() => handleStartPart(1)} className="p-8 rounded-[2rem] bg-slate-900 border border-slate-800 hover:border-indigo-500 transition-all text-left group">
              <BookOpen className="text-indigo-400 mb-4 group-hover:scale-110 transition-transform" />
              <h3 className="text-xl font-bold text-white mb-2">Part 1: Interview</h3>
              <p className="text-sm text-slate-500">General conversation in English.</p>
