          <button onClick={handleGlobalExit} className="mt-12 text-slate-500 font-bold uppercase tracking-widest text-xs flex items-center gap-2 mx-auto hover:text-white transition-colors"><ArrowLeft size={14} /> Back to Dashboard</button>
        </div>
