          <div className="grid md:grid-cols-2 gap-6">
            <button onClick={startRandomQuestion} className="p-10 rounded-[2.5rem] bg-indigo-600 hover:bg-indigo-500 transition-all text-center group shadow-2xl shadow-indigo-500/20">
              <Zap size={40} className="text-white mx-auto mb-6 group-hover:scale-110 transition-transform" />
              <h3 className="text-2xl font-black text-white mb-2">Instant Random</h3>
              <p className="text-indigo-100/60 text-sm">Let the examiner surprise you with a random English topic.</p>
            </button>
            <button onClick={() => setStage('category-selection')} className="p-10 rounded-[2.5rem] bg-slate-900 border border-slate-800 hover:border-indigo-500 transition-all text-center group">
              <LayoutGrid size={40} className="text-indigo-400 mx-auto mb-6 group-hover:scale-110 transition-transform" />
              <h3 className="text-2xl font-black text-white mb-2">Topic Library</h3>
              <p className="text-slate-500 text-sm">Choose a specific domain for your English audit.</p>
            </button>
          </div>
          <button onClick={() => setStage('selection')} className="mt-12 text-slate-500 font-bold uppercase tracking-widest text-[10px] flex items-center gap-2 mx-auto hover:text-white transition-colors"><ArrowLeft size={14} /> Back to Part Selection</button>
        </div>
      )}

      {stage === 'category-selection' && (
        <div className="max-w-5xl w-full animate-in fade-in zoom-in duration-500">
          <header className="flex justify-between items-end mb-10">
            <div>
              <h2 className="text-4xl font-black text-white italic tracking-tighter mb-2">English Topics</h2>
              <p className="text-slate-500">Select a category for your official simulation.</p>
            </div>
            <button onClick={() => setStage('method-selection')} className="text-indigo-400 font-black uppercase tracking-widest text-[10px] flex items-center gap-2 hover:text-white transition-colors"><ArrowLeft size={14} /> Back</button>
          </header>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
            {Object.keys(part === 1 ? IELTS_QUESTIONS.part1 : IELTS_QUESTIONS.part2).map((cat) => (
              <button 
                key={cat} 
                onClick={() => { setSelectedCategory(cat); setStage('question-selection'); }}
                className="aspect-square p-6 rounded-3xl bg-slate-900 border border-slate-800 hover:border-indigo-500/50 hover:bg-slate-800 transition-all flex flex-col items-center justify-center text-center group"
              >
                <div className="w-12 h-12 rounded-2xl bg-slate-950 border border-slate-800 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                  <Hash size={20} className="text-indigo-500" />
