                <span className="text-xs font-bold text-slate-300 group-hover:text-white transition-colors">{cat}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {stage === 'question-selection' && (
        <div className="max-w-4xl w-full animate-in fade-in slide-in-from-right-4 duration-500">
          <header className="flex justify-between items-center mb-10 border-b border-slate-900 pb-8">
            <div className="flex items-center gap-4">
              <div className="p-3 rounded-2xl bg-indigo-600/10 text-indigo-400">
                <Search size={24} />
              </div>
              <div>
                <h2 className="text-2xl font-bold text-white italic">{selectedCategory}</h2>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">English prompt selection</p>
              </div>
            </div>
            <button onClick={() => setStage('category-selection')} className="text-indigo-400 font-black uppercase tracking-widest text-[10px] flex items-center gap-2 hover:text-white transition-colors"><ArrowLeft size={14} /> Back to Categories</button>
          </header>
          <div className="space-y-3 max-h-[60vh] overflow-y-auto pr-4 custom-scrollbar">
            {(part === 1 ? IELTS_QUESTIONS.part1 : IELTS_QUESTIONS.part2 as any)[selectedCategory!].map((q: any, i: number) => (
              <button 
                key={i} 
                onClick={() => beginQuestion(q)}
                className="w-full p-6 rounded-2xl bg-slate-900 border border-slate-800 hover:border-indigo-500/50 hover:bg-slate-900/50 transition-all text-left group flex items-center justify-between"
              >
                <span className="text-slate-300 group-hover:text-white transition-colors line-clamp-1 italic">
                  {typeof q === 'string' ? q : q.topic}
                </span>
                <ChevronRight size={18} className="text-slate-700 group-hover:text-indigo-400 transition-all" />
              </button>
            ))}
          </div>
        </div>
      )}

      {stage === 'question' && (
        <div className="max-w-2xl w-full text-center animate-in fade-in duration-500">
          <div className="relative mx-auto w-24 h-24 mb-8">
             <Volume2 size={48} className={`absolute inset-0 m-auto transition-all duration-500 ${isSpeaking ? 'text-indigo-400 scale-110' : 'text-slate-700'}`} />
             {isSpeaking && (
               <div className="absolute inset-0 rounded-full border-2 border-indigo-500/30 animate-ping" />
             )}
          </div>
          <h2 className="text-2xl font-bold text-white mb-4">Examiner is speaking (English)...</h2>

          {isFetchingAudio ? (
            <div className="flex items-center justify-center gap-2 text-indigo-400 mb-10">
               <Loader2 size={16} className="animate-spin" />
               <span className="text-[10px] font-black uppercase tracking-widest">Securing AI Audio Pipeline...</span>
            </div>
          ) : (
            <div className="flex items-center justify-center gap-2 text-emerald-400 mb-10">
               <Headphones size={16} className="animate-pulse" />
               <span className="text-[10px] font-black uppercase tracking-widest">UK Examiner Native Active</span>
            </div>
          )}

          <div className="p-8 rounded-3xl bg-slate-900/50 border border-slate-800 italic text-slate-400 mb-12 min-h-[100px] flex items-center justify-center">
            {showText ? `"${typeof question === 'string' ? question : question?.topic}"` : "Official prompt audio active..."}
          </div>
          <button onClick={() => setStage(part === 1 ? 'recording' : 'prep')} disabled={isSpeaking || isFetchingAudio} className="px-12 py-5 rounded-full bg-indigo-600 text-white font-bold transition-all disabled:opacity-30 shadow-xl shadow-indigo-600/20 active:scale-95">
            {part === 1 ? "Start Answering" : "Begin Preparation"}
          </button>
          <button onClick={() => setShowText(!showText)} className="block mt-6 mx-auto text-[10px] font-black uppercase text-slate-600 hover:text-slate-400 tracking-widest">Toggle Script</button>
        </div>
      )}

      {stage === 'prep' && (
        <div className="max-w-2xl w-full text-center">
          <div className="w-24 h-24 border-4 border-indigo-500 rounded-full flex items-center justify-center mx-auto mb-8 shadow-[0_0_20px_rgba(99,102,241,0.2)]">
            <span className="text-3xl font-black text-white">{prepTime}</span>
          </div>
          <h2 className="text-2xl font-bold text-white mb-8 italic">Preparation Phase</h2>
          <div className="p-10 rounded-[2.5rem] bg-slate-900 border-2 border-slate-800 text-left mb-10 shadow-2xl relative overflow-hidden">
            <ExaminerStatusIndicator state={getExaminerState()} />
            <p className="text-xl text-white font-bold mb-6 italic pt-16">"{question?.topic}"</p>
            <ul className="space-y-3">
              {question?.points?.map((p: string, i: number) => <li key={i} className="text-slate-400 text-sm flex gap-3 items-center"><span className="w-1.5 h-1.5 rounded-full bg-indigo-500" /> {p}</li>)}
            </ul>
          </div>
          <button onClick={() => setStage('recording')} className="px-10 py-4 rounded-full bg-indigo-600 font-bold hover:bg-indigo-500 transition-all active:scale-95 shadow-xl">Start Answering</button>
        </div>
      )}

      {stage === 'recording' && (
        <div className="w-full max-w-4xl flex flex-col items-center">
          <div className="w-full relative rounded-[3rem] overflow-hidden bg-black aspect-video border-4 border-slate-900 shadow-2xl">
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
            <canvas ref={canvasRef} className="absolute inset-0 w-full h-full pointer-events-none z-10" />

            <ExaminerStatusIndicator state={getExaminerState()} />

            {(!isAiLoopActive) && (
              <div className="absolute inset-0 bg-slate-950/90 flex flex-col items-center justify-center z-50 backdrop-blur-md">
                <Loader2 className="text-indigo-500 animate-spin mb-4" size={40} />
                <p className="text-white font-black tracking-[0.3em] uppercase text-[10px]">Applying Secure Guard-Rails...</p>
              </div>
            )}

            {isAiLoopActive && <ZenOverlay metrics={faceMetrics} />}

            <div className="absolute top-8 left-8 flex items-center gap-2 bg-indigo-600 px-3 py-1 rounded-full z-30">
               <span className="text-[9px] font-black uppercase text-white">English Mode Active</span>
            </div>

            <div className="absolute bottom-8 right-8 bg-black/60 backdrop-blur-md border border-white/10 px-6 py-3 rounded-2xl text-2xl font-mono text-white shadow-2xl z-30">
              {Math.floor(recordTime/60).toString().padStart(2,'0')}:{(recordTime%60).toString().padStart(2,'0')}
            </div>
          </div>
          <button onClick={handleStop} disabled={!isAiLoopActive} className="mt-12 px-12 py-5 rounded-full bg-slate-900 border-2 border-slate-800 text-rose-400 font-bold hover:bg-rose-500/10 transition-all flex items-center gap-4 active:scale-95 shadow-xl">
             <div className="w-3 h-3 bg-rose-500 rounded-sm" /> End Task & Analyze (English)
          </button>
        </div>
      )}

      {stage === 'processing' && (
        <div className="text-center animate-in fade-in duration-500">
          <div className="relative w-20 h-20 mx-auto mb-10">
             <div className="absolute inset-0 border-4 border-indigo-500/10 rounded-full" />
             <div className="absolute inset-0 border-4 border-t-indigo-500 rounded-full animate-spin" />
             <Loader2 size={40} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-400 animate-pulse" />
          </div>
          <h2 className="text-3xl font-black text-white mb-4 italic tracking-tight">Syncing Examiner Audit...</h2>
          <p className="text-slate-500 max-xs mx-auto">Evaluating content relevance with authenticated App-Check tokens.</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { 
  Award, 
  BarChart3, 
  CheckCircle, 
  ArrowRight, 
  RotateCcw, 
  MessageSquare,
  Zap,
  ShieldAlert,
  ChevronRight,
  TrendingUp,
  Brain,
  Languages,
  Loader2,
  Eye,
  Split,
  Download,
  QrCode,
  Share2,
  Clock,
  Sparkles,
  Target,
  Trophy,
  BrainCircuit,
  ShieldCheck,
  ArrowLeft,
  X,
  Languages as LanguagesIcon
} from 'lucide-react';
import { AnalysisMetrics, LanguageConfig } from '../types';
import { SUPPORTED_LANGUAGES } from '../constants';
import { GoogleGenAI, Type } from "@google/genai";
import html2canvas from 'html2canvas';
import { coachService } from '../lib/aiService';

interface IELTSReportViewProps {
  data: AnalysisMetrics;
  onNext: () => void;
  onRetry: () => void;
  onExit: () => void;
}

export const IELTSReportView: React.FC<IELTSReportViewProps> = ({ data, onNext, onRetry, onExit }) => {
  const [targetLang, setTargetLang] = useState<LanguageConfig>(SUPPORTED_LANGUAGES[0]);
  const [isTranslating, setIsTranslating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [translatedTips, setTranslatedTips] = useState<string[] | null>(null);
  const [showTranslated, setShowTranslated] = useState(false);
  const [viewMode, setViewMode] = useState<'single' | 'comparison'>('single');

  const shareRef = useRef<HTMLDivElement>(null);

  const subscores = data.ielts_subscores || { fluency: 6.5, lexical: 7.0, grammar: 6.0, pronunciation: 7.5 };

  const isEarlyBird = useMemo(() => {
    const hours = new Date().getHours();
    return hours >= 4 && hours <= 6;
  }, []);

  const downloadReport = async () => {
    if (!shareRef.current) return;
    setIsDownloading(true);
    try {
      const canvas = await html2canvas(shareRef.current, {
        backgroundColor: '#020617',
        scale: 2,
        logging: false,
        useCORS: true,
        allowTaint: true,
        windowWidth: 800,
        windowHeight: 1100
      });
      const link = document.createElement('a');
      link.download = `FluencyCoach_BattleReport_${data.id.slice(0, 5)}.png`;
      link.href = canvas.toDataURL('image/png', 0.9);
      link.click();
    } catch (err) {
      console.error("Export failure", err);
      alert("Failed to generate Battle Card. Please try again.");
    } finally {
      setIsDownloading(false);
    }
  };

  const translateFeedback = async (lang: LanguageConfig) => {
    if (lang.code === 'en') {
      setTranslatedTips(null);
      setShowTranslated(false);
      return;
    }

    setIsTranslating(true);
    try {
      const ai = coachService.getAI();
      const prompt = `Translate the following IELTS examiner feedback from English to ${lang.label}. 
      Original Tips: ${data.feedback_tips.join(' | ')}

      Maintain a professional, formal examiner tone in ${lang.label}. 
      Return ONLY valid JSON with an array of translated tips.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              translated_tips: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["translated_tips"]
          }
        }
      });

      const result = JSON.parse(response.text || '{}');
      if (result.translated_tips) {
        setTranslatedTips(result.translated_tips);
        setShowTranslated(true);
      }
    } catch (err) {
      console.error("Translation failed", err);
    } finally {
      setIsTranslating(false);
    }
  };

  const handleLangChange = (lang: LanguageConfig) => {
    setTargetLang(lang);
