import { useState, useEffect } from 'react';

export interface User {
  uid: string;
  displayName: string;
  email: string;
  isAnonymous: boolean;
}

/**
 * Mock Auth Hook: Replaces Firebase Authentication for a 100% client-side experience.
 * Always returns a persistent "Demo User" to keep the app functional without a backend.
 */
export const useAuth = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if we have an anonymous ID stored
    let anonId = localStorage.getItem('fluency_coach_anon_id');
    if (!anonId) {
      anonId = `demo_user_${Math.random().toString(36).substring(2, 10)}`;
      localStorage.setItem('fluency_coach_anon_id', anonId);
    }

    const demoUser: User = {
      uid: anonId,
      displayName: "Elite Fluency Demo",
      email: "demo@fluencycoach.local",
      isAnonymous: true
    };

    // Simulate small delay for loading state consistency
    const timer = setTimeout(() => {
      setUser(demoUser);
      setLoading(false);
    }, 500);

    return () => clearTimeout(timer);
  }, []);

  return { user, loading };
};

import { Dexie, type Table } from 'dexie';
import { AnalysisMetrics } from '../types';

/**
 * Client-Side Database: Replaces Firestore for local persistence.
 */
export class StorageDatabase extends Dexie {
  sessions!: Table<AnalysisMetrics>;

  constructor() {
    super('FluencyCoachStorage');
    this.version(1).stores({
      sessions: 'id, date, userId, language, ielts_score'
    });
  }
}

export const localDb = new StorageDatabase();

export const StorageService = {
  /**
   * Saves a coaching session locally.
   */
  async saveSession(report: AnalysisMetrics) {
    try {
      await localDb.sessions.put(report);
      return report.id;
    } catch (error) {
      console.error("Storage Error:", error);
      throw error;
    }
  },

  /**
   * Retrieves session history for the demo user.
   */
  async getHistory(uid: string): Promise<AnalysisMetrics[]> {
    try {
      return await localDb.sessions
        .where('userId')
        .equals(uid)
        .reverse()
        .sortBy('date');
    } catch (error) {
      console.error("Fetch Error:", error);
      return [];
    }
  },

  /**
   * Deletes a record from the browser.
   */
  async deleteSession(id: string) {
    try {
      await localDb.sessions.delete(id);
    } catch (error) {
      console.error("Delete Error:", error);
    }
  },

  /**
   * Tracks user streaks and session counts in LocalStorage.
   */
  getStreak() {
    return parseInt(localStorage.getItem('fluency_streak') || '0', 10);
  },

  incrementStreak() {
    const current = this.getStreak();
    localStorage.setItem('fluency_streak', (current + 1).toString());
    return current + 1;
  }
};

