import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisMetrics } from "../types";

/**
 * LinguisticCoachService: The primary engine for communication coaching.
 * Consolidates all Gemini API interactions for client-side execution.
 */
export class LinguisticCoachService {
  /**
   * Internal helper to get a fresh AI instance.
   * Resiliently looks for API keys in standard Vite and mapped process.env locations.
   */
  public getAI() {
    // Check both mapped process.env and Vite's native import.meta.env
    const apiKey = (import.meta as any).env?.VITE_GEMINI_API_KEY || process.env.API_KEY;

    if (!apiKey || apiKey === "undefined" || apiKey === "") {
      console.error("Gemini API Key is missing. Ensure VITE_GEMINI_API_KEY is set in your hosting environment variables.");
      throw new Error("Gemini API Key is missing. Please check your environment variables (VITE_GEMINI_API_KEY).");
    }

    return new GoogleGenAI({ apiKey });
  }

  async analyzeSpeech(
    base64Audio: string, 
    mimeType: string, 
    config: {
      language: string;
      context: string;
      duration: number;
      eyeContact: number;
      smile: number;
      sampleArticle?: string | null;
    }
  ): Promise<Partial<AnalysisMetrics>> {
    const ai = this.getAI();

    const systemInstruction = `You are an elite linguistic coach. Analyze the audio for fluency, emotion, and pace. Output MUST be valid JSON.`;
    const userPrompt = `Audit this ${config.duration}s sample in ${config.language}. 
    Context: ${config.context}. 
    Biometrics: Eye Contact ${config.eyeContact.toFixed(1)}%, Smile ${config.smile.toFixed(1)}%.
    ${config.sampleArticle ? `Reading Task: "${config.sampleArticle}"` : "Spontaneous speech."}`;

    // Use gemini-3-pro-preview for complex reasoning and linguistic analysis tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          parts: [
            { text: userPrompt },
            { inlineData: { mimeType, data: base64Audio } }
          ]
        }
      ],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            transcription: { type: Type.STRING },
            wpm: { type: Type.NUMBER },
            ielts_score: { type: Type.NUMBER },
            cefr_level: { type: Type.STRING },
            feedback_tips: { type: Type.ARRAY, items: { type: Type.STRING } },
            emotion: { type: Type.STRING },
            emotion_confidence: { type: Type.NUMBER },
            emotion_explanation: { type: Type.STRING },
            vocal_energy: { type: Type.NUMBER },
            pitch_range: { type: Type.NUMBER },
            emotional_stability: { type: Type.NUMBER }
          },
          required: ["transcription", "wpm", "ielts_score", "cefr_level", "feedback_tips", "emotion", "emotion_confidence", "emotion_explanation", "vocal_energy", "pitch_range", "emotional_stability"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI. Check your model selection and API Key permissions.");
    return JSON.parse(text);
  }

  async analyzeIELTS(
    base64Audio: string,
    mimeType: string,
    config: {
      part: number;
      question: string;
      duration: number;
    }
  ): Promise<Partial<AnalysisMetrics>> {
    const ai = this.getAI();

    const prompt = `Official IELTS examiner audit for Part ${config.part}.
    Question: "${config.question}".
    Evaluate fluency, lexical resource, and pronunciation. Output MUST be valid JSON.`;

    // Use gemini-3-pro-preview for advanced reasoning in standardized exam evaluation
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          parts: [
            { text: prompt },
            { inlineData: { mimeType, data: base64Audio } }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            transcription: { type: Type.STRING },
            wpm: { type: Type.NUMBER },
            ielts_score: { type: Type.NUMBER },
            cefr_level: { type: Type.STRING },
            feedback_tips: { type: Type.ARRAY, items: { type: Type.STRING } },
            emotion: { type: Type.STRING },
            emotion_confidence: { type: Type.NUMBER },
            emotion_explanation: { type: Type.STRING },
            vocal_energy: { type: Type.NUMBER },
            pitch_range: { type: Type.NUMBER },
            emotional_stability: { type: Type.NUMBER }
          },
          required: ["transcription", "wpm", "ielts_score", "cefr_level", "feedback_tips", "emotion", "emotion_confidence", "emotion_explanation", "vocal_energy", "pitch_range", "emotional_stability"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI. Ensure you are using the correct gemini-3 models.");
    return JSON.parse(text);
  }
}

