               <div className="w-3 h-3 bg-rose-500 rounded-sm" /> End Task & Analyze
            </button>
          )}
        </div>
      )}

      {stage === 'processing' && (
        <div className="text-center">
          <Loader2 size={40} className="text-indigo-400 animate-spin mx-auto mb-10" />
